<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Assess Your Password Strength</title>
  <style>
    .strength-meter {
      width: 100%;
      height: 20px;
      background-color: #ddd;
      border-radius: 10px;
      overflow: hidden;
    }
    .meter-bar {
      height: 100%;
      background-color: green;
      transition: width 0.3s ease;
    }
    p {
      margin-top: 10px;
    }
  </style>
</head>
<body>
