      if (hasLowercase && hasUppercase) strength += 2;
      if (hasNumber) strength += 1;
      if (hasSpecialChar) strength += 1;

      return strength;
    }

    document.getElementById('passwordInput').addEventListener('input', function() {
      const password = this.value;
      const strength = assessPasswordStrength(password);

      const meterBar = document.querySelector('.meter-bar');
      const feedbackMessage = document.getElementById('feedbackMessage');

      switch (true) {
        case strength <= 2:
          meterBar.style.width = '20%';
          feedbackMessage.textContent = 'Weak: Improve your password strength.';
          break;
        case strength <= 4:
          meterBar.style.width = '50%';
          feedbackMessage.textContent = 'Moderate: Good, but can be stronger.';
          break;
        default:
          meterBar.style.width = '100%';
          feedbackMessage.textContent = 'Strong: Great job!';
      }
    });
  </script>
</body>
</html>
```

